def fear_response(threat_level):
    if threat_level <= 0:
        return "No fear detected."
    elif threat_level < 5:
        return "Alert: Assess situation and prepare to act."
    elif threat_level < 10:
        return "Fight-or-flight response triggered."
    else:
        return "Freeze or paralysis response activated."

# Example usage:
print(fear_response(3))  # Output: Alert: Assess situation and prepare to act.
print(fear_response(8))  # Output: Fight-or-flight response triggered.
